import{_ as l,o as a,c as e,a9 as s}from"./chunks/framework.STMWz9Nm.js";const c=JSON.parse('{"title":"Redis缓存设计","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/04-数据库与中间件能力/06-Redis缓存设计.md","filePath":"语言/java/04-数据库与中间件能力/06-Redis缓存设计.md","lastUpdated":1777106511000}'),h={name:"语言/java/04-数据库与中间件能力/06-Redis缓存设计.md"};function r(n,i,t,d,p,k){return a(),e("div",null,[...i[0]||(i[0]=[s(`<h1 id="redis缓存设计" tabindex="-1">Redis缓存设计 <a class="header-anchor" href="#redis缓存设计" aria-label="Permalink to “Redis缓存设计”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>缓存设计是围绕 Redis 构建高性能读写链路的一套方法。<br> 它不仅是“把数据放进去”，更包含过期、更新、一致性和高可用思考。</p><p>一句话理解：</p><ul><li>缓存不是简单副本</li><li>它是数据库前面的一层带有时效性和风险控制的减压层</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>缓存设计得好，系统吞吐和响应时间会明显改善。<br> 设计不好，则会带来这些经典问题：</p><ul><li>缓存穿透</li><li>缓存击穿</li><li>缓存雪崩</li><li>热点数据打爆数据库</li><li>缓存和数据库不一致</li></ul><p>所以缓存不是“加了就快”，而是要带着稳定性思维去设计。</p><h2 id="_3-先建立直觉-缓存不是数据真相来源" tabindex="-1">3. 先建立直觉：缓存不是数据真相来源 <a class="header-anchor" href="#_3-先建立直觉-缓存不是数据真相来源" aria-label="Permalink to “3. 先建立直觉：缓存不是数据真相来源”">​</a></h2><p>学习缓存设计时，最重要的一条原则是：</p><ul><li>数据真相通常在数据库</li><li>缓存更多是性能层和减压层</li></ul><p>这意味着：</p><ul><li>你不能只关心命中率</li><li>还要关心失效策略、更新策略、一致性兜底和异常流量</li></ul><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-缓存穿透" tabindex="-1">4.1 缓存穿透 <a class="header-anchor" href="#_4-1-缓存穿透" aria-label="Permalink to “4.1 缓存穿透”">​</a></h3><p>缓存穿透指的是：</p><ul><li>请求的数据根本不存在</li><li>缓存里没有</li><li>数据库里也没有</li><li>结果每次都直接打到数据库</li></ul><p>常见应对：</p><ul><li>缓存空值</li><li>布隆过滤器</li><li>参数合法性校验</li></ul><h3 id="_4-2-缓存击穿" tabindex="-1">4.2 缓存击穿 <a class="header-anchor" href="#_4-2-缓存击穿" aria-label="Permalink to “4.2 缓存击穿”">​</a></h3><p>缓存击穿通常指：</p><ul><li>某个热点 key 失效了</li><li>大量请求同时来查这个 key</li><li>所有请求一起打到数据库</li></ul><p>常见应对：</p><ul><li>热点 key 互斥重建</li><li>热点数据不过期或逻辑过期</li><li>提前刷新</li></ul><h3 id="_4-3-缓存雪崩" tabindex="-1">4.3 缓存雪崩 <a class="header-anchor" href="#_4-3-缓存雪崩" aria-label="Permalink to “4.3 缓存雪崩”">​</a></h3><p>缓存雪崩通常指：</p><ul><li>大量 key 在同一时间集中失效</li><li>大量请求一起穿透到数据库</li></ul><p>常见应对：</p><ul><li>过期时间加随机值</li><li>多级缓存</li><li>限流降级</li><li>热点数据提前预热</li></ul><h3 id="_4-4-缓存一致性" tabindex="-1">4.4 缓存一致性 <a class="header-anchor" href="#_4-4-缓存一致性" aria-label="Permalink to “4.4 缓存一致性”">​</a></h3><p>缓存一致性是最重要、也最难完全做绝对强一致的部分之一。</p><p>常见思路包括：</p><ul><li>先更新数据库，再删除缓存</li><li>先删缓存，再更新数据库</li><li>延迟双删</li><li>订阅 binlog / 消息异步更新缓存</li></ul><p>学习阶段最重要的是先知道：</p><ul><li>一致性通常不是“自动拥有”</li><li>它必须被设计出来</li></ul><h3 id="_4-5-热点数据" tabindex="-1">4.5 热点数据 <a class="header-anchor" href="#_4-5-热点数据" aria-label="Permalink to “4.5 热点数据”">​</a></h3><p>热点数据的问题在于：</p><ul><li>访问集中</li><li>瞬时并发高</li><li>一个 key 就能成为系统瓶颈</li></ul><p>常见处理思路：</p><ul><li>永不过期或逻辑过期</li><li>本地缓存 + Redis 双层缓存</li><li>热点 key 分片</li><li>专项预热和限流</li></ul><h3 id="_4-6-过期策略与淘汰策略" tabindex="-1">4.6 过期策略与淘汰策略 <a class="header-anchor" href="#_4-6-过期策略与淘汰策略" aria-label="Permalink to “4.6 过期策略与淘汰策略”">​</a></h3><p>这两个概念容易混淆。</p><h4 id="过期策略" tabindex="-1">过期策略 <a class="header-anchor" href="#过期策略" aria-label="Permalink to “过期策略”">​</a></h4><p>关注的是：</p><ul><li>一个 key 到了 TTL 后怎么处理</li></ul><h4 id="淘汰策略" tabindex="-1">淘汰策略 <a class="header-anchor" href="#淘汰策略" aria-label="Permalink to “淘汰策略”">​</a></h4><p>关注的是：</p><ul><li>内存不够时，Redis 要淘汰哪些 key</li></ul><p>所以：</p><ul><li>过期是按时间</li><li>淘汰是按容量压力</li></ul><h2 id="_5-学习重点" tabindex="-1">5. 学习重点 <a class="header-anchor" href="#_5-学习重点" aria-label="Permalink to “5. 学习重点”">​</a></h2><p>这一章最重要的是掌握：</p><ul><li>缓存是减压层，不是最终真相层</li><li>穿透、击穿、雪崩是三种不同问题</li><li>一致性设计永远是重点</li><li>热点数据必须专项处理</li><li>缓存方案必须结合访问特征和失败场景设计</li></ul><h2 id="_6-常见问题" tabindex="-1">6. 常见问题 <a class="header-anchor" href="#_6-常见问题" aria-label="Permalink to “6. 常见问题”">​</a></h2><h3 id="_6-1-只加缓存-不设计失效策略" tabindex="-1">6.1 只加缓存，不设计失效策略 <a class="header-anchor" href="#_6-1-只加缓存-不设计失效策略" aria-label="Permalink to “6.1 只加缓存，不设计失效策略”">​</a></h3><p>这样早晚会遇到：</p><ul><li>数据脏</li><li>热点失控</li><li>难以排查</li></ul><h3 id="_6-2-遇到一致性问题没有兜底手段" tabindex="-1">6.2 遇到一致性问题没有兜底手段 <a class="header-anchor" href="#_6-2-遇到一致性问题没有兜底手段" aria-label="Permalink to “6.2 遇到一致性问题没有兜底手段”">​</a></h3><p>如果没有：</p><ul><li>重试</li><li>延迟删除</li><li>异步修正</li></ul><p>一致性问题通常会反复出现。</p><h3 id="_6-3-热点数据没有专项处理" tabindex="-1">6.3 热点数据没有专项处理 <a class="header-anchor" href="#_6-3-热点数据没有专项处理" aria-label="Permalink to “6.3 热点数据没有专项处理”">​</a></h3><p>很多系统平时都正常，一到活动或流量峰值就崩，热点 key 往往是原因之一。</p><h2 id="_7-一套最常用的缓存旁路思路" tabindex="-1">7. 一套最常用的缓存旁路思路 <a class="header-anchor" href="#_7-一套最常用的缓存旁路思路" aria-label="Permalink to “7. 一套最常用的缓存旁路思路”">​</a></h2><p>最常见的 Cache Aside 思路可以先这样记：</p><ol><li>读请求先查缓存</li><li>缓存没有，再查数据库</li><li>查到后写入缓存</li><li>写请求先更新数据库</li><li>更新后删除缓存</li></ol><p>这不是唯一方案，但它是最常见的起点。</p><h2 id="_8-动手验证" tabindex="-1">8. 动手验证 <a class="header-anchor" href="#_8-动手验证" aria-label="Permalink to “8. 动手验证”">​</a></h2><p>当前环境没有 <code>redis-cli</code>，所以这篇我把重点放在“方案演练步骤”和“可复制命令”上。<br> 如果你本地有 Redis，可以直接按下面做演练。</p><h3 id="_8-1-模拟缓存穿透" tabindex="-1">8.1 模拟缓存穿透 <a class="header-anchor" href="#_8-1-模拟缓存穿透" aria-label="Permalink to “8.1 模拟缓存穿透”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:999999</span></span></code></pre></div><p>如果数据库里也没有这个用户，那么你应该思考：</p><ul><li>是否要缓存空值</li><li>空值 TTL 多久合适</li></ul><h3 id="_8-2-模拟缓存击穿设计思路" tabindex="-1">8.2 模拟缓存击穿设计思路 <a class="header-anchor" href="#_8-2-模拟缓存击穿设计思路" aria-label="Permalink to “8.2 模拟缓存击穿设计思路”">​</a></h3><p>热点 key：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> product:1001</span></span></code></pre></div><p>演练问题：</p><ul><li>如果这个 key 突然过期，同时 1 万个请求来查，谁去重建？</li><li>是所有人一起查库，还是只有一个人查，其他人等待或降级？</li></ul><h3 id="_8-3-模拟缓存雪崩设计思路" tabindex="-1">8.3 模拟缓存雪崩设计思路 <a class="header-anchor" href="#_8-3-模拟缓存雪崩设计思路" aria-label="Permalink to “8.3 模拟缓存雪崩设计思路”">​</a></h3><p>如果你批量设置缓存：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> item:1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> item:2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> item:3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span></span></code></pre></div><p>那 600 秒后它们可能一起失效。<br> 更好的做法往往是：</p><ul><li>在 TTL 基础上加随机偏移</li></ul><p>例如设计成：</p><ul><li>600 ~ 660 秒随机过期</li></ul><h3 id="_8-4-一致性方案演练" tabindex="-1">8.4 一致性方案演练 <a class="header-anchor" href="#_8-4-一致性方案演练" aria-label="Permalink to “8.4 一致性方案演练”">​</a></h3><p>假设更新用户信息的流程是：</p><ol><li>更新数据库</li><li>删除缓存 <code>user:1</code></li></ol><p>你应该重点思考：</p><ul><li>删除缓存失败怎么办</li><li>数据库更新成功但缓存删除失败怎么办</li><li>是否需要重试或异步补偿</li></ul><h2 id="_9-练习建议" tabindex="-1">9. 练习建议 <a class="header-anchor" href="#_9-练习建议" aria-label="Permalink to “9. 练习建议”">​</a></h2><p>下面这些练习做完，这一章会更扎实：</p><ul><li>设计一个缓存旁路方案</li><li>模拟缓存击穿和雪崩场景</li><li>总结缓存更新和失效的几种常见策略</li><li>为热点 key 设计一套专项保护方案</li></ul><h2 id="_10-自测问题" tabindex="-1">10. 自测问题 <a class="header-anchor" href="#_10-自测问题" aria-label="Permalink to “10. 自测问题”">​</a></h2><ul><li>缓存穿透、击穿、雪崩的区别是什么？</li><li>为什么缓存一致性永远是重点问题？</li><li>热点数据为什么需要特殊处理？</li><li>为什么缓存不是数据真相来源？</li><li>过期策略和淘汰策略有什么区别？</li></ul><h2 id="_11-自测核对要点" tabindex="-1">11. 自测核对要点 <a class="header-anchor" href="#_11-自测核对要点" aria-label="Permalink to “11. 自测核对要点”">​</a></h2><p>如果你的回答能覆盖下面这些点，说明这一章基本掌握到位了：</p><ul><li>穿透是查不存在数据，击穿是热点 key 失效，雪崩是大量 key 集中过期</li><li>缓存一致性需要显式设计，不能默认拥有</li><li>热点数据会把单 key 问题放大成系统问题</li><li>缓存方案要同时考虑命中率、更新、一致性和故障兜底</li><li>过期和淘汰是两个不同维度的策略</li></ul>`,99)])])}const b=l(h,[["render",r]]);export{c as __pageData,b as default};
